/**
 * notificationScheduler.js
 *
 * Automated push notifications (all times in IST = UTC+5:30):
 *
 *  • Good Morning     — 8:00 AM every day, AI-generated
 *  • Festival Check   — 8:05 AM every day, Groq checks if today is an Indian festival
 *  • Learning Nudge   — weekly, 4 randomly chosen days (max 1-day gap between them),
 *                       times selected from {10,13,16,20} with at most one repeat
 *  • Good Night       — 11:00 PM every day, AI-generated
 *
 * All message content is generated by Groq (llama-3.1-8b-instant).
 * Schedule stored in app_config so it survives restarts.
 */

import OpenAI from "openai";
import { sendPushBroadcast } from "./push.js";
import { query } from "./db.js";

// ── Task AI client (OpenAI-compatible, configured via env vars) ───────────────
const taskAI = new OpenAI({
  baseURL: process.env.TASK_AI_BASE_URL || "https://api.groq.com/openai/v1",
  apiKey:  process.env.TASK_AI_API_KEY  || process.env.GROQ_API_KEY || "missing-task-ai-key",
});
const TASK_AI_MODEL = process.env.TASK_AI_MODEL || "llama-3.1-8b-instant";

// ── IST helpers (IST = UTC + 330 min) ────────────────────────────────────────
function nowIST() {
  return new Date(Date.now() + 330 * 60 * 1000);
}

function istDateStr(d) {
  return d.toISOString().slice(0, 10);
}

function isoWeekKey(d) {
  const tmp = new Date(d);
  tmp.setUTCHours(0, 0, 0, 0);
  tmp.setUTCDate(tmp.getUTCDate() + 4 - (tmp.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(tmp.getUTCFullYear(), 0, 1));
  const week = Math.ceil(((tmp - yearStart) / 86400000 + 1) / 7);
  return `${tmp.getUTCFullYear()}-W${String(week).padStart(2, "0")}`;
}

// ── In-memory fired guard (prevents double-send within same minute) ───────────
const _fired = new Set();

function firedKey(type, dateStr) {
  return `${type}::${dateStr}`;
}

function alreadyFired(type, dateStr) {
  return _fired.has(firedKey(type, dateStr));
}

function markFired(type, dateStr) {
  _fired.add(firedKey(type, dateStr));
  if (_fired.size > 200) {
    const first = _fired.values().next().value;
    _fired.delete(first);
  }
}

// ── Language picker ───────────────────────────────────────────────────────────
// Distribution: English 43%, Hinglish 35%, RomanHindi 20%, RomanTamil 3%
// Internal IDs avoid the word "Hindi"/"Tamil" so the AI doesn't default to native scripts.
const LANG_POOL = [
  ...Array(43).fill("English"),
  ...Array(35).fill("Hinglish"),
  ...Array(20).fill("RomanHindi"),
  ...Array(3).fill("RomanTamil"),
];

function pickLanguage() {
  return LANG_POOL[Math.floor(Math.random() * LANG_POOL.length)];
}

