// ── Groq AI content generation ────────────────────────────────────────────────
const ROMAN_SYSTEM_MSG =
  "CRITICAL RULE: You must write ALL text exclusively in the Roman/Latin alphabet (A-Z). " +
  "This means NO Devanagari script (Hindi/Sanskrit), NO Tamil script, NO Arabic script, and NO other non-Latin scripts. " +
  "Even when the language is Hindi or Tamil, you MUST write every word phonetically using only English/Roman letters. " +
  "If you use any non-Latin character, your response is invalid. Only A-Z, numbers, spaces, punctuation, and emojis are allowed.";

// Detects Devanagari, Tamil, Arabic, Cyrillic, CJK, and other non-Latin scripts
// (does NOT flag emojis — emojis are fine)
function hasNonLatin(str) {
  return /[\u0250-\u02AF\u0370-\u03FF\u0400-\u04FF\u0500-\u05FF\u0600-\u06FF\u0900-\u097F\u0980-\u09FF\u0A00-\u0A7F\u0A80-\u0AFF\u0B00-\u0B7F\u0B80-\u0BFF\u0C00-\u0C7F\u0C80-\u0CFF\u0D00-\u0D7F\u0E00-\u0E7F\u4E00-\u9FFF\u3000-\u303F]/.test(str);
}

// Strip non-Latin script characters from a string (keep emojis, spaces, A-Z, punctuation)
function stripNonLatin(str) {
  return str
    .replace(/[\u0250-\u02AF\u0370-\u03FF\u0400-\u04FF\u0500-\u05FF\u0600-\u06FF\u0900-\u097F\u0980-\u09FF\u0A00-\u0A7F\u0A80-\u0AFF\u0B00-\u0B7F\u0B80-\u0BFF\u0C00-\u0C7F\u0C80-\u0CFF\u0D00-\u0D7F\u0E00-\u0E7F\u4E00-\u9FFF\u3000-\u303F]/g, "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

async function groqJSONRaw(messages) {
  const res = await taskAI.chat.completions.create({
    model: TASK_AI_MODEL,
    messages,
    temperature: 0.9,
    max_tokens: 200,
    response_format: { type: "json_object" },
  });
  const text = res.choices[0]?.message?.content || "{}";
  try { return JSON.parse(text); } catch { return {}; }
}

async function groqJSON(prompt) {
  const messages = [
    { role: "system", content: ROMAN_SYSTEM_MSG },
    { role: "user",   content: prompt },
  ];
  let result = await groqJSONRaw(messages);

  // ── Pass 1: retry in pure English if non-Latin detected ──────────────────
  const combined = `${result.title || ""} ${result.body || ""}`;
  if (hasNonLatin(combined)) {
    console.warn("[notify] non-Latin script detected — retrying in English");
    result = await groqJSONRaw([
      { role: "system", content: ROMAN_SYSTEM_MSG },
      {
        role: "user",
        content:
          "You must write ONLY using A-Z letters (Roman/English alphabet).\n" +
          "Absolutely NO Devanagari, Tamil, Arabic, or any other script.\n" +
          "Language: English only.\n\n" + prompt,
      },
    ]);
  }

  // ── Pass 2: strip any remaining non-Latin chars as final safety ──────────
  const title = stripNonLatin(result.title || "");
  const body  = stripNonLatin(result.body  || "");

  return { title, body };
}

export async function generateMorningMessage() {
  const d = nowIST();
  const days = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
  const day = days[d.getUTCDay()];
  const lang = pickLanguage();
  return groqJSON(
    `You write warm, short push notifications for CrLearn — a clinical reasoning training app for final-year Indian medical students (NEET-PG aspirants).

Generate a good morning message for ${day}. It should feel personal, encouraging, and medically themed.

Language rule: ${LANG_INSTRUCTIONS[lang]}

Emoji rule: Include 1–2 fitting emojis in the title AND 1–2 fitting emojis somewhere in the body. They should feel natural, not forced.

Rules: title ≤ 45 chars (including emojis), body ≤ 100 chars (including emojis).
Return JSON: {"title":"...","body":"..."}`
  );
}

