export async function checkTodayFestival() {
  const d = nowIST();
  const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const humanDate = `${d.getUTCDate()} ${months[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
  const days = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
  const dayName = days[d.getUTCDay()];

  const res = await groqJSON(
    `Today is ${humanDate} (${dayName}). You know all Indian festivals, cultural days, religious observances, and special days (Holi, Diwali, Eid, Durga Puja, Navratri, Rose Day, Valentine's Day, Friendship Day, Doctors' Day, etc.).

Is today a notable Indian festival, cultural event, or special day? Consider regional, national, and internationally celebrated days observed in India.
If YES: return JSON {"festival":"<name>","celebrate":true}
If NO:  return JSON {"festival":null,"celebrate":false}
Only return a festival if you are highly confident it falls today (${humanDate}).`
  );

  return res?.celebrate ? (res.festival || null) : null;
}

