// ── Weekly nudge schedule ─────────────────────────────────────────────────────
function buildValidDayCombos() {
  const combos = [];
  for (let a = 0; a <= 4; a++)
    for (let b = a + 1; b <= 5; b++) if (b - a <= 2)
      for (let c = b + 1; c <= 6; c++) if (c - b <= 2)
        for (let d = c + 1; d <= 6; d++) if (d - c <= 2)
          combos.push([a, b, c, d]);
  return combos;
}

const VALID_COMBOS = buildValidDayCombos();

export function generateWeekSchedule(istNow) {
  const now = istNow || nowIST();

  const dayOffsets = VALID_COMBOS[Math.floor(Math.random() * VALID_COMBOS.length)];

  const baseTimes = [10, 13, 16, 20];
  const dupIdx  = Math.floor(Math.random() * 4);
  let dropIdx;
  do { dropIdx = Math.floor(Math.random() * 4); } while (dropIdx === dupIdx);
  const times = [...baseTimes.filter((_, i) => i !== dropIdx), baseTimes[dupIdx]];
  for (let i = times.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [times[i], times[j]] = [times[j], times[i]];
  }

  const dow = now.getUTCDay();
  const daysToMon = dow === 0 ? -6 : 1 - dow;
  const monday = new Date(now.getTime() + daysToMon * 86400000);

  return dayOffsets.map((offset, i) => {
    const d = new Date(monday.getTime() + offset * 86400000);
    return { date: istDateStr(d), hour: times[i] };
  });
}

async function loadSchedule() {
  const { rows } = await query(
    `SELECT value FROM app_config WHERE key = 'nudge_schedule'`
  );
  if (!rows[0]) return null;
  try { return JSON.parse(rows[0].value); } catch { return null; }
}

async function saveSchedule(schedule) {
  await query(
    `INSERT INTO app_config (key, value) VALUES ('nudge_schedule', $1)
     ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value`,
    [JSON.stringify(schedule)]
  );
}

export async function ensureWeekSchedule() {
  const existing = await loadSchedule();
  const week = isoWeekKey(nowIST());

  if (existing?.week === week && Array.isArray(existing?.slots) && existing.slots.length === 4) {
    return existing.slots;
  }

  const slots = generateWeekSchedule();
  await saveSchedule({ week, slots });
  console.log("[notify] new weekly nudge schedule:", JSON.stringify(slots));
  return slots;
}

export async function getScheduleInfo() {
  const slots = await ensureWeekSchedule();
  return { week: isoWeekKey(nowIST()), slots };
}

// ── Scheduler on/off toggle (persisted in app_config) ────────────────────────
export async function getSchedulerEnabled() {
  const { rows } = await query(
    `SELECT value FROM app_config WHERE key = 'notify_scheduler_enabled'`
  );
  return rows[0]?.value !== "false";
}

export async function setSchedulerEnabled(enabled) {
  await query(
    `INSERT INTO app_config (key, value) VALUES ('notify_scheduler_enabled', $1)
     ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value`,
    [String(Boolean(enabled))]
  );
  console.log(`[notify] scheduler ${enabled ? "enabled" : "disabled"} by admin`);
  return Boolean(enabled);
}

// ── Notification runners ──────────────────────────────────────────────────────
export async function runMorningNotification({ force = false } = {}) {
  const dateStr = istDateStr(nowIST());
  if (!force && alreadyFired("morning", dateStr)) return { skipped: "already_sent" };
  markFired("morning", dateStr);

  try {
    const msg = await generateMorningMessage();
    const title = msg.title || "Good Morning ☀️";
    const body  = msg.body  || "Start your day strong — one case a day keeps failure away.";
    const result = await sendPushBroadcast({ title, body, link: "/dashboard", kind: "morning", tag: "daily-morning" });
    console.log(`[notify] morning sent — ${result.sent}/${result.total}`);
    return { ok: true, title, body, ...result };
  } catch (e) {
    console.warn("[notify] morning failed:", e.message);
    return { ok: false, error: e.message };
  }
}

export async function runNightNotification({ force = false } = {}) {
  const dateStr = istDateStr(nowIST());
  if (!force && alreadyFired("night", dateStr)) return { skipped: "already_sent" };
  markFired("night", dateStr);

  try {
    const msg = await generateNightMessage();
    const title = msg.title || "Good Night 🌙";
    const body  = msg.body  || "Rest well. Your brain consolidates learning as you sleep.";
    const result = await sendPushBroadcast({ title, body, link: "/dashboard", kind: "night", tag: "daily-night" });
    console.log(`[notify] night sent — ${result.sent}/${result.total}`);
    return { ok: true, title, body, ...result };
  } catch (e) {
    console.warn("[notify] night failed:", e.message);
    return { ok: false, error: e.message };
  }
}

export async function runFestivalCheck({ force = false } = {}) {
  const dateStr = istDateStr(nowIST());
  if (!force && alreadyFired("festival", dateStr)) return { skipped: "already_checked" };
  markFired("festival", dateStr);

  try {
    const festival = await checkTodayFestival();
    if (!festival) {
      console.log("[notify] festival check — no festival today");
      return { ok: true, festival: null };
    }
    console.log(`[notify] festival detected: ${festival}`);
    const msg = await generateFestivalMessage(festival);
    const title = msg.title || `Happy ${festival}! 🎉`;
    const body  = msg.body  || `Wishing you and your family a wonderful ${festival}.`;
    const result = await sendPushBroadcast({ title, body, link: "/dashboard", kind: "festival", tag: "festival-greeting" });
    console.log(`[notify] festival push sent — ${result.sent}/${result.total}`);
    return { ok: true, festival, title, body, ...result };
  } catch (e) {
    console.warn("[notify] festival check failed:", e.message);
    return { ok: false, error: e.message };
  }
}

export async function runFestivalForced(festivalName) {
  try {
    const msg = await generateFestivalMessage(festivalName);
    const title = msg.title || `Happy ${festivalName}! 🎉`;
    const body  = msg.body  || `Wishing you and your family a wonderful ${festivalName}.`;
    const result = await sendPushBroadcast({ title, body, link: "/dashboard", kind: "festival", tag: "festival-greeting" });
    return { ok: true, festival: festivalName, title, body, ...result };
  } catch (e) {
    return { ok: false, error: e.message };
  }
}

export async function runNudgeNotification({ force = false } = {}) {
  try {
    const msg = await generateNudgeMessage();
    const title = msg.title || "Time to Practice 🩺";
    const body  = msg.body  || "A quick case is waiting. Keep your streak alive!";
    const result = await sendPushBroadcast({ title, body, link: "/practice", kind: "nudge", tag: "weekly-nudge" });
    console.log(`[notify] nudge sent — ${result.sent}/${result.total}`);
    return { ok: true, title, body, ...result };
  } catch (e) {
    console.warn("[notify] nudge failed:", e.message);
    return { ok: false, error: e.message };
  }
}

// ── Main scheduler loop ───────────────────────────────────────────────────────
let _started = false;

export function startNotificationScheduler() {
  if (_started) return;
  _started = true;

  async function tick() {
    try {
      const ist  = nowIST();
      const hour = ist.getUTCHours();
      const min  = ist.getUTCMinutes();
      const dateStr = istDateStr(ist);

      // ── Skip everything if scheduler is disabled ─────────────────────────
      const enabled = await getSchedulerEnabled();
      if (!enabled) return;

      // ── 8:00 AM IST → Good Morning ──────────────────────────────────────
      if (hour === 8 && min < 5) {
        await runMorningNotification();
      }

      // ── 8:05 AM IST → Festival check ────────────────────────────────────
      if (hour === 8 && min >= 5 && min < 10) {
        await runFestivalCheck();
      }

      // ── Weekly nudge slots ───────────────────────────────────────────────
      if ([10, 13, 16, 20].includes(hour) && min < 5) {
        const nudgeKey = `nudge::${dateStr}::${hour}`;
        if (!_fired.has(nudgeKey)) {
          const slots = await ensureWeekSchedule();
          const match = slots.find((s) => s.date === dateStr && s.hour === hour);
          if (match) {
            _fired.add(nudgeKey);
            await runNudgeNotification();
          }
        }
      }

      // ── 11:00 PM IST → Good Night ───────────────────────────────────────
      if (hour === 23 && min < 5) {
        await runNightNotification();
      }

      // ── Sunday 11:50 PM IST → Pre-generate next week's schedule ─────────
      if (ist.getUTCDay() === 0 && hour === 23 && min >= 50) {
        const nextKey = `schedule-gen::${dateStr}`;
        if (!_fired.has(nextKey)) {
          _fired.add(nextKey);
          const nextMonday = new Date(ist.getTime() + 1 * 86400000);
          const slots = generateWeekSchedule(nextMonday);
          const week  = isoWeekKey(nextMonday);
          await saveSchedule({ week, slots });
          console.log("[notify] pre-generated next week schedule:", JSON.stringify(slots));
        }
      }

    } catch (e) {
      console.warn("[notify] scheduler tick error:", e.message);
    }
  }

  setTimeout(tick, 20_000);
  setInterval(tick, 5 * 60 * 1000);
  console.log("[notify] notification scheduler started (IST timezone)");
}
